"use client";

// src/components/RainbowKitProvider/useFingerprint.ts
import { useCallback, useEffect } from "react";
var storageKey = "rk-version";
function setRainbowKitVersion({ version }) {
  if (typeof window !== "undefined") {
    window.localStorage.setItem(storageKey, version);
  }
}
function useFingerprint() {
  const fingerprint = useCallback(() => {
    setRainbowKitVersion({ version: "__buildVersion" });
  }, []);
  useEffect(() => {
    fingerprint();
  }, [fingerprint]);
}

export {
  useFingerprint
};
